     *    → `StructuredCallMode.TextOnly`.
     *
     * 4. Anything else → `StructuredCallMode.Skip`.
     *
     * After rule selection two post-rule promotions apply (in order):
     *
     * - `user_force_vision` promotes `TextOnly` → `TextPlusVision`
     *   (`Skip` stays `Skip` — caller meant to opt out).
     *
     * - `enable_vision_fallback` promotes `TextOnly` →
     *   `TextOnlyWithVisionFallback` (does **not** upgrade `TextPlusVision` or
     *   `Skip`).
     */
    fun chooseCallMode(input: StructuredInput, t: StructuredThresholds): StructuredCallMode {
        val resultJson = KreuzbergBridge.nativeChooseCallMode(mapper.writeValueAsString(input), mapper.writeValueAsString(t))
        return mapper.readValue(resultJson, StructuredCallMode::class.java)
    }
    /**
     * Decide which call mode best fits this document.
     *
     * Rules applied in order:
     *
     * 1. `image/ *` → `StructuredCallMode.VisionOnly` (no text layer to start from).
     * 2. `application/pdf` → `StructuredCallMode.TextOnly` regardless of
     *    `text_coverage` or embedded image count.  Kreuzberg's OCR + text-layer
     *    extraction produces text for scanned PDFs; the orchestrator's
     *    post-call confidence gate handles any vision escalation actually needed.
     *
     * 3. DOCX / `text/html` / `text/ *` / `application/json` / `application/xml` /
     *    `application/rtf` with `avg_chars_per_page > docx_text_min_density`
     *    → `StructuredCallMode.TextOnly`.
     *
     * 4. Anything else → `StructuredCallMode.Skip`.
     *
     * After rule selection two post-rule promotions apply (in order):
     *
     * - `user_force_vision` promotes `TextOnly` → `TextPlusVision`
     *   (`Skip` stays `Skip` — caller meant to opt out).
     *
     * - `enable_vision_fallback` promotes `TextOnly` →
     *   `TextOnlyWithVisionFallback` (does **not** upgrade `TextPlusVision` or
     *   `Skip`).
     */
    suspend fun chooseCallModeAsync(input: StructuredInput, t: StructuredThresholds): StructuredCallMode =
        withContext(Dispatchers.IO) { chooseCallMode(input, t) }
    /**
     * Calculate a chunking plan for a document.
     *
     * **Returns:**
     *
     * A `ChunkPlan` with optimal chunk boundaries.
     */
    fun calculateChunkPlan(pageCount: Int, sizeBytes: Long, needsOcr: Boolean, config: HeuristicsConfig): ChunkPlan {
        val resultJson = KreuzbergBridge.nativeCalculateChunkPlan(pageCount, sizeBytes, needsOcr, mapper.writeValueAsString(config))
        return mapper.readValue(resultJson, ChunkPlan::class.java)
    }
    /**
     * Calculate a chunking plan for a document.
     *
     * **Returns:**
     *
     * A `ChunkPlan` with optimal chunk boundaries.
     */
    suspend fun calculateChunkPlanAsync(pageCount: Int, sizeBytes: Long, needsOcr: Boolean, config: HeuristicsConfig): ChunkPlan =
        withContext(Dispatchers.IO) { calculateChunkPlan(pageCount, sizeBytes, needsOcr, config) }
    /**
     * Calculate a chunk plan from user-specified page ranges.
     *
     * Validates and processes user overrides into a proper chunk plan.
     */
    fun calculatePlanFromOverrides(userChunks: List<PageRange>, totalPages: Int, sizeBytes: Long, config: HeuristicsConfig): ChunkPlan {
        val resultJson = KreuzbergBridge.nativeCalculatePlanFromOverrides(mapper.writeValueAsString(userChunks), totalPages, sizeBytes, mapper.writeValueAsString(config))
        return mapper.readValue(resultJson, ChunkPlan::class.java)
    }
    /**
     * Calculate a chunk plan from user-specified page ranges.
     *
     * Validates and processes user overrides into a proper chunk plan.
     */
    suspend fun calculatePlanFromOverridesAsync(userChunks: List<PageRange>, totalPages: Int, sizeBytes: Long, config: HeuristicsConfig): ChunkPlan =
        withContext(Dispatchers.IO) { calculatePlanFromOverrides(userChunks, totalPages, sizeBytes, config) }
    /** Stable sha256 fingerprint of `raw`, formatted as `sha256:<hex>`. */
    fun fingerprint(raw: ByteArray): String = KreuzbergBridge.nativeFingerprint(java.util.Base64.getEncoder().encodeToString(raw))
    /**
     * Resolve `(preset, custom_schema_override, context)` into a `ResolvedPreset`.
     *
     * - `custom_schema` overrides `preset.schema` when set.
     * - `context` substitutes `{{key}}` tokens in `preset.context_template`; the
     *   rendered string is appended to `system_prompt` so the model sees it.
     */
    fun resolve(preset: Preset, customSchema: String? = null, context: Map<String, String>): ResolvedPreset {
        val resultJson = KreuzbergBridge.nativeResolve(mapper.writeValueAsString(preset), customSchema ?: "", mapper.writeValueAsString(context))
        return mapper.readValue(resultJson, ResolvedPreset::class.java)
    }
    /**
     * Resolve `(preset, custom_schema_override, context)` into a `ResolvedPreset`.
     *
     * - `custom_schema` overrides `preset.schema` when set.
     * - `context` substitutes `{{key}}` tokens in `preset.context_template`; the
     *   rendered string is appended to `system_prompt` so the model sees it.
     */
    suspend fun resolveAsync(preset: Preset, customSchema: String? = null, context: Map<String, String>): ResolvedPreset =
        withContext(Dispatchers.IO) { resolve(preset, customSchema, context) }
    /**
     * Extract structured JSON from a document using JSON-encoded preset spec and options.
     *
     * This is the synchronous JSON-in / JSON-out entry point suitable for FFI and
     * language-binding call paths.
     *
     *   `cache`).  Pass `"{}"` to use all defaults.
     *
     * **Returns:**
     *
     * JSON-serialised `StructuredOutput` on success.
     *
     * **Errors:**
     *
     * Returns `Validation` when either JSON argument is
     * malformed.  All other failures from the underlying
     * `extract_structured_sync` call are mapped onto `KreuzbergError`
     * via `From<StructuredError>`.
     */
    fun extractStructuredJson(bytes: ByteArray, mime: String, presetSpecJson: String, optionsJson: String): String = KreuzbergBridge.nativeExtractStructuredJson(java.util.Base64.getEncoder().encodeToString(bytes), mime, presetSpecJson, optionsJson)
    /**
     * Split a multi-document PDF and extract structured JSON from each segment,
     * returning a JSON array of `StructuredOutput` objects.
     *
     * Non-PDF documents are passed through as a single-element array.
     *
     * Same as `extract_structured_json`.
     *
     * **Returns:**
     *
     * JSON-serialised `List<StructuredOutput>` (a JSON array) on success.
     *
     * **Errors:**
     *
     * Returns `Validation` when either JSON argument is
     * malformed.  All other failures from the underlying
     * `split_and_extract_sync` call are mapped onto `KreuzbergError`
     * via `From<StructuredError>`.
     */
    fun splitAndExtractJson(bytes: ByteArray, mime: String, presetSpecJson: String, optionsJson: String): String = KreuzbergBridge.nativeSplitAndExtractJson(java.util.Base64.getEncoder().encodeToString(bytes), mime, presetSpecJson, optionsJson)
    /**
     * Render a single PDF page to PNG bytes.
     *
     * Returns raw PNG-encoded bytes for the specified page at the given DPI.
     * Uses pdf_oxide with tiny-skia for pure-Rust rendering.
     *
     * For pages with extreme dimensions (very wide vector diagrams, etc.) the
     * effective DPI may be automatically reduced to avoid rasterizer failure.
     * A warning is logged when this happens.
     *
     * **Errors:**
     *
     * Returns `KreuzbergError.Parsing` if the PDF cannot be opened, authenticated,
     * or rendered, or if `page_index` is out of range.
     */
    fun renderPdfPageToPng(pdfBytes: ByteArray, pageIndex: Long, dpi: Int? = null, password: String? = null): ByteArray = KreuzbergBridge.nativeRenderPdfPageToPng(java.util.Base64.getEncoder().encodeToString(pdfBytes), pageIndex, dpi ?: 0, password ?: "")
    /**
     * Caption a single image from bytes.
     *
     *   `RegionKind.Caption` prompt when `null`.
     *
     * **Returns:**
     *
     * The generated caption text.
     *
     * **Errors:**
     *
     * Returns an error if the VLM call fails or if image format detection fails.
     */
    fun captionImage(imageBytes: ByteArray, llmConfig: LlmConfig, customPrompt: String? = null): String = KreuzbergBridge.nativeCaptionImage(java.util.Base64.getEncoder().encodeToString(imageBytes), mapper.writeValueAsString(llmConfig), customPrompt ?: "")
    /**
     * Caption a single image from a file path.
     *
     *   `RegionKind.Caption` prompt when `null`.
     *
     * **Returns:**
     *
     * The generated caption text.
